mapper.update:
UPDATE task
inspection_id = #{inspectionId}, repairman_id = #{repairmanId}, area_id = #{areaId}, pipe_id = #{pipeId}, pipe_segment_id = #{pipeSegmentId}, task_name = #{taskName}, type = #{type}, priority = #{priority}, status = #{status}, public_time = #{publicTime}, response_time = #{responseTime}, accomplish_time = #{accomplishTime}, feedback_information = #{feedbackInformation}, update_time = #{updateTime},
WHERE id = #{id}

mapper.select:
SELECT CAST(( SELECT COUNT(*) FROM task t
AND ( (MOD(#{areaId}, 10000) = 0 AND t.area_id BETWEEN #{areaId} AND #{areaId} + 9999) OR (MOD(#{areaId}, 10000) != 0 AND MOD(#{areaId}, 100) = 0 AND t.area_id BETWEEN #{areaId} AND #{areaId} + 99) OR (MOD(#{areaId}, 100) != 0 AND t.area_id = #{areaId}) )
) AS CHAR) AS total, CAST(( SELECT COUNT(*) FROM task t WHERE t.status = 0
AND ( (MOD(#{areaId}, 10000) = 0 AND t.area_id BETWEEN #{areaId} AND #{areaId} + 9999) OR (MOD(#{areaId}, 10000) != 0 AND MOD(#{areaId}, 100) = 0 AND t.area_id BETWEEN #{areaId} AND #{areaId} + 99) OR (MOD(#{areaId}, 100) != 0 AND t.area_id = #{areaId}) )
) AS CHAR) AS pending, CAST(( SELECT COUNT(*) FROM task t WHERE t.status = 1
AND ( (MOD(#{areaId}, 10000) = 0 AND t.area_id BETWEEN #{areaId} AND #{areaId} + 9999) OR (MOD(#{areaId}, 10000) != 0 AND MOD(#{areaId}, 100) = 0 AND t.area_id BETWEEN #{areaId} AND #{areaId} + 99) OR (MOD(#{areaId}, 100) != 0 AND t.area_id = #{areaId}) )
) AS CHAR) AS in_progress, CAST(( SELECT COUNT(*) FROM task t WHERE t.status = 2
AND ( (MOD(#{areaId}, 10000) = 0 AND t.area_id BETWEEN #{areaId} AND #{areaId} + 9999) OR (MOD(#{areaId}, 10000) != 0 AND MOD(#{areaId}, 100) = 0 AND t.area_id BETWEEN #{areaId} AND #{areaId} + 99) OR (MOD(#{areaId}, 100) != 0 AND t.area_id = #{areaId}) )
) AS CHAR) AS completed, CAST(( SELECT COUNT(*) FROM task t WHERE t.priority = 1
AND ( (MOD(#{areaId}, 10000) = 0 AND t.area_id BETWEEN #{areaId} AND #{areaId} + 9999) OR (MOD(#{areaId}, 10000) != 0 AND MOD(#{areaId}, 100) = 0 AND t.area_id BETWEEN #{areaId} AND #{areaId} + 99) OR (MOD(#{areaId}, 100) != 0 AND t.area_id = #{areaId}) )
) AS CHAR) AS urgent
